mapper.update:
UPDATE snackRequest
SET status = 'DELETED'
WHERE snackId = #{snackId}

mapper.select:
SELECT COUNT(*) FROM snackRequest WHERE status != 'DELETED'
AND status = #{status, jdbcType=VARCHAR}
AND (itemName LIKE '%' || #{keyword} || '%' OR reason LIKE '%' || #{keyword} || '%')

mapper.delete:
DELETE FROM snackVote
WHERE snackId = #{snackId}
  AND empId = #{empId, jdbcType=VARCHAR}

mapper.select:
SELECT COUNT(*) FROM snackVote
WHERE snackId = #{snackId}
  AND empId = #{empId, jdbcType=VARCHAR}
